#!/usr/bin/env python3
"""kaching-tell REAL FIX (post-final, based on live feed diagnostics).

Root cause found in the live World Cup final feed:
  * Goals are NOT in Stats[1001]/[1002] (those are period/stat-type slots that
    stayed 0 all match). The real goal count lives in the Score object:
    Score.Participant1.Total.Goals (home) / Score.Participant2.Total.Goals (away),
    with flat Stats[1]/[2] as a fallback. parseScore now reads those -> score,
    verification and scorer attribution work against the real feed.
  * Anchoring used sendAndConfirmTransaction, which needs the websocket method
    signatureSubscribe that Alchemy does not support -> anchors landed on-chain but
    looked failed. Now submits + confirms over HTTP (getSignatureStatuses).

Also updates the simulator to the real Score shape and removes the diagnostic.
Safe to re-run. Usage: python3 fix_real.py [/path/to/repo]"""
import base64, os, sys, shutil, subprocess, datetime, glob
FILES = {
    'src/utils/score.js': "",
    'src/anchor/anchor.js': "",
    'scripts/simulate.js': "",
    'package.json': "",
}

def find_repo(a):
    if len(a)>1: return os.path.abspath(a[1])
    here=os.path.abspath(os.path.dirname(__file__))
    for c in (here, os.path.expanduser("~/kaching-tell"), os.getcwd()):
        if os.path.isdir(os.path.join(c,"src")) and os.path.isfile(os.path.join(c,"package.json")): return c
    return here
def main():
    repo=find_repo(sys.argv)
    if not os.path.isdir(os.path.join(repo,"src")): print("ERROR: run in repo or pass path"); sys.exit(1)
    stamp=datetime.datetime.now().strftime("%Y%m%d-%H%M%S")
    bak=os.path.join(repo,".realfix-backup-"+stamp); os.makedirs(bak,exist_ok=True)
    for rel,b64 in FILES.items():
        dest=os.path.join(repo,rel); os.makedirs(os.path.dirname(dest),exist_ok=True)
        if os.path.exists(dest): shutil.copy2(dest, os.path.join(bak, rel.replace("/","__")))
        open(dest,"wb").write(base64.b64decode(b64)); print("  wrote "+rel)
    # remove the diagnostic + old backup folders
    diag=os.path.join(repo,"scripts/diag.js")
    if os.path.exists(diag): os.remove(diag); print("  removed scripts/diag.js")
    for d in glob.glob(os.path.join(repo,".diag-backup-*"))+glob.glob(os.path.join(repo,".fix*-backup-*")):
        shutil.rmtree(d, ignore_errors=True); print("  removed "+os.path.basename(d))
    node=shutil.which("node")
    if node:
        print("\nSyntax check:")
        for rel in ("src/utils/score.js","src/anchor/anchor.js","scripts/simulate.js"):
            r=subprocess.run([node,"-c",os.path.join(repo,rel)],capture_output=True,text=True)
            print(("  OK   " if r.returncode==0 else "  FAIL ")+rel+("" if r.returncode==0 else "\n"+r.stderr))
    print("\nDone. Verify:  node scripts/simulate.js   (expect 10 verified, progressive 0-1..4-6)")
    print("Then:  git add -A && git commit -m \"Fix score mapping (Score object) + Alchemy-safe anchoring\" && git push")
    print("Backup:", bak)
if __name__=="__main__": main()
